/**
 * Official Type definitions for CalendarJS
 * https://calendarjs.com
 */

import Calendar from './types/calendar/index';
import Schedule from './types/schedule/index';
import Timeline from './types/timeline/index';
import Event from './types/schedule/event';

interface Helpers {
    /** Transform a number into two digits string */
    two(value: number | string): string;
    /** Check if a date object is valid */
    isValidDate(d: Date): boolean;
    /** Check if a string is in valid YYYY-MM-DD format */
    isValidDateFormat(date: string): boolean;
    /** Convert a date to string format YYYY-MM-DD HH:MM:SS */
    toString(date: Date | number[], dateOnly?: boolean): string;
    /** Convert a date string to array [y, m, d, h, i, s] */
    toArray(value: string): number[];
    /** Convert array to string date */
    arrayToStringDate(arr: number[]): string;
    /** Convert JavaScript date to Excel serial number */
    dateToNum(jsDate: Date | string): number;
    /** Convert Excel serial number to date string or array */
    numToDate(excelSerialNumber: number, asArray?: boolean): string | number[];
    /** Convert date to relative time string (e.g., "5m ago") */
    prettify(d: string, texts?: {
        justNow?: string;
        xMinutesAgo?: string;
        xHoursAgo?: string;
        xDaysAgo?: string;
        xWeeksAgo?: string;
        xMonthsAgo?: string;
        xYearsAgo?: string;
    }): string;
    /** Apply prettify to all elements with .prettydate class */
    prettifyAll(): void;
    /** Alias for toString */
    now(date?: Date | number[]): string;
    /** Localized weekday names (Sunday-Saturday) */
    readonly weekdays: string[];
    /** Localized short weekday names (Sun-Sat) */
    readonly weekdaysShort: string[];
    /** Localized month names (January-December) */
    readonly months: string[];
    /** Localized short month names (Jan-Dec) */
    readonly monthsShort: string[];
}

interface About {
    name: string;
    version: string;
    url: string;
}

declare const calendarjs: {
    Calendar: typeof Calendar;
    Schedule: typeof Schedule;
    Timeline: typeof Timeline;
    Event: typeof Event;
    Helpers: Helpers;
    /** Set translations for calendar labels */
    setDictionary: (dictionary: Record<string, string>) => void;
    /** Library information */
    about: () => About;
};

export default calendarjs;
